"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

const tabs = [
  { href: "/admin", label: "Orders" },
  { href: "/admin/products", label: "Products" },
  { href: "/admin/tabs", label: "Tabs" },
];

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  return (
    <div className="min-h-screen">
      <header className="header">
        <div className="max-w-3xl mx-auto px-4 py-3 flex items-center justify-between">
          <h1 className="text-xl font-bold">Lucky Store Admin</h1>
          <Link href="/" className="text-sm text-white/60 hover:text-white transition-colors">View Store &rarr;</Link>
        </div>
        <nav className="max-w-3xl mx-auto px-4">
          <div className="flex gap-1">
            {tabs.map(tab => (
              <Link key={tab.href} href={tab.href} className={`px-4 py-2.5 text-sm font-medium rounded-t-lg transition-colors ${
                pathname === tab.href ? "bg-[var(--c-bg)] text-gray-900" : "text-white/50 hover:text-white"
              }`}>{tab.label}</Link>
            ))}
          </div>
        </nav>
      </header>
      <main className="max-w-3xl mx-auto px-4 py-6">{children}</main>
    </div>
  );
}
